import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Header from './Components/Header';
import Register from './Pages/Auth/Register';
import Login from './Pages/Auth/Login';
import './index.css';

function App() {
  return (
    <BrowserRouter>
      <Header />
      
      <Routes>
        <Route path="/" element={<h1 style={{textAlign: 'center', padding: '2rem'}}>الصفحة الرئيسية</h1>} />
        <Route path="/courses" element={<h1 style={{textAlign: 'center', padding: '2rem'}}>صفحة الكورسات</h1>} />
        <Route path="/pricing" element={<h1 style={{textAlign: 'center', padding: '2rem'}}>صفحة الأسعار</h1>} />
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
